const results = [];
const originalItems = $('Preserve Opportunity Data').all();

for (let i = 0; i < $input.all().length; i++) {
  const cb = $input.all()[i].json;
  const orig = originalItems[i] ? originalItems[i].json : {};
  const clearbitOk = !!cb.name;

  results.push({ json: {
    opportunity_id: orig.opportunity_id || '',
    company_name: (clearbitOk ? cb.name : null) || orig.company_name || '',
    company_domain: (clearbitOk ? cb.domain : null) || orig.company_domain || '',
    job_title: orig.job_title || '',
    job_description: orig.job_description || '',
    location: orig.location || '',
    seniority: orig.seniority || '',
    skills: orig.skills || '',
    match_score: orig.match_score || '',
    source_url: orig.source_url || '',
    source_name: orig.source_name || '',
    employment_type: orig.employment_type || '',
    posted_date: orig.posted_date || '',
    date_found: orig.date_found || '',
    company_classification: orig.company_classification || '',
    company_classification_reason: orig.company_classification_reason || '',
    status: orig.status || '',
    company_summary: clearbitOk ? (cb.description || '').substring(0, 500) : '',
    company_industry: clearbitOk ? (cb.category?.industry || cb.category?.sector || '') : '',
    company_employee_count: clearbitOk ? (cb.metrics?.employees || 0) : 0,
    company_annual_revenue: clearbitOk ? (cb.metrics?.annualRevenue || 0) : 0,
    _clearbit_success: clearbitOk
  }});
}
return results;

const results = [];
const TITLE_PRIORITY = {
  engineering: ['Engineering Manager', 'Director of Engineering', 'VP of Engineering', 'VP Engineering', 'CTO', 'Head of Engineering', 'Tech Lead Manager', 'Software Development Manager', 'Principal Engineer'],
  data: ['Director of Data', 'VP of Data', 'Head of Data', 'Data Engineering Manager', 'Director of Analytics', 'VP Analytics', 'Chief Data Officer'],
  product: ['VP of Product', 'Director of Product', 'Head of Product', 'CPO', 'Product Director', 'VP Product Management'],
  operations: ['COO', 'VP Operations', 'Director of Operations', 'Head of Operations', 'Operations Director'],
  finance: ['CFO', 'VP Finance', 'Director of Finance', 'Controller', 'Head of Finance'],
  default: ['Director', 'VP', 'Vice President', 'Head of', 'Department Head', 'Talent Acquisition Manager', 'Recruiting Manager', 'HR Manager']
};

// Size filter thresholds
const MAX_ANNUAL_REVENUE = 100000000;  // $100MM
const MAX_EMPLOYEES = 1000;            // proxy when revenue unavailable

for (const item of $input.all()) {
  const job = { ...item.json };

  // Filter out large/enterprise companies
  const revenue = job.company_annual_revenue || 0;
  const employees = job.company_employee_count || 0;

  if (revenue > 0 && revenue > MAX_ANNUAL_REVENUE) {
    // Revenue data available and over threshold — skip
    continue;
  }
  if (revenue === 0 && employees > MAX_EMPLOYEES) {
    // No revenue data but employee count is enterprise-level — skip
    continue;
  }

  const titleLower = (job.job_title || '').toLowerCase();
  const descLower = (job.job_description || '').toLowerCase();
  let domain = 'default';
  if (/engineer|developer|devops|sre|platform|infrastructure/.test(titleLower)) domain = 'engineering';
  else if (/data|analytics|ml|machine learning|ai/.test(titleLower)) domain = 'data';
  else if (/product|ux|design/.test(titleLower)) domain = 'product';
  else if (/operations|ops/.test(titleLower)) domain = 'operations';
  else if (/finance|accounting|financial/.test(titleLower)) domain = 'finance';

  job._title_priority = [...(TITLE_PRIORITY[domain] || []), ...TITLE_PRIORITY.default];
  job._hiring_signals = [];
  if (/growing|scaling|hypergrowth|series [a-e]|recently funded/.test(descLower)) job._hiring_signals.push('Company in growth phase');
  if (/remote|hybrid|work from home/.test(descLower)) job._hiring_signals.push('Offers remote/hybrid work');
  if (/urgent|immediate|asap|start immediately/.test(descLower)) job._hiring_signals.push('Urgent hire needed');
  if (/contract|c2h|contract.to.hire/.test(descLower)) job._hiring_signals.push('Open to contract/C2H');
  job._tech_stack = ['react','node','python','java','go','rust','typescript','kubernetes','aws','azure','gcp','terraform','postgres','mysql','mongodb'].filter(t => descLower.includes(t));
  job._role_domain = domain;
  results.push({ json: job });
}
return results;

const opportunityItems = $('Extract Hiring Signals').all();
const results = [];

for (let idx = 0; idx < $input.all().length; idx++) {
  const hunterData = $input.all()[idx].json;
  const opportunity = opportunityItems[idx] ? opportunityItems[idx].json : {};
  const emails = hunterData.data?.emails || [];
  const titlePriority = opportunity._title_priority || [];

  if (emails.length === 0) {
    results.push({ json: {
      ...opportunity,
      contact_name: '', contact_title: '', contact_email: '', contact_phone: '', linkedin_url: '',
      source_of_contact: opportunity.company_domain ? 'hunter.io (no results)' : 'hunter.io (no domain)',
      confidence_score: 0,
      contact_reasoning: 'No contacts found via Hunter.io domain search'
    }});
    continue;
  }

  const scored = emails.map(email => {
    let score = 30;
    const title = (email.position || '').toLowerCase();
    for (let i = 0; i < titlePriority.length; i++) {
      if (title.includes(titlePriority[i].toLowerCase())) { score += Math.max(10, 50 - i * 5); break; }
    }
    if (email.confidence) score += Math.floor(email.confidence / 10);
    if (['director','vp','head','manager'].some(t => title.includes(t))) score += 10;
    return { ...email, _score: score };
  });
  scored.sort((a, b) => b._score - a._score);
  const best = scored[0];

  results.push({ json: {
    ...opportunity,
    contact_name: `${best.first_name || ''} ${best.last_name || ''}`.trim(),
    contact_title: best.position || '',
    contact_email: best.value || '',
    contact_phone: '',
    linkedin_url: best.linkedin || '',
    source_of_contact: 'hunter.io',
    confidence_score: best._score,
    contact_reasoning: `Best match from ${emails.length} contacts: title score + Hunter confidence ${best.confidence || 0}%`
  }});
}
return results;

// Only pass items with a valid opportunity_id, real contact email, and confidence >= 70
return $input.all().filter(item => 
  !!item.json.opportunity_id &&
  !!item.json.contact_email &&
  (item.json.confidence_score || item.json.hunter_confidence || 0) >= 70
);

// Accept any truthy approved value: true, 'TRUE', 'approved', 'yes', '1', 1
function isApproved(v) {
  if (!v && v !== 0) return false;
  if (v === true || v === 1) return true;
  const s = String(v).trim().toLowerCase();
  return ['true', 'approved', 'yes', '1'].includes(s);
}

return $input.all()
  .filter(item => isApproved(item.json.approved))
  .map(item => ({ json: { ...item.json } }));

// Update Opportunity Status only returns 3 fields.
// Write to Contacts Sheet only returns contact fields (no company_name, job_title, etc.)
// Fix: match back to Score & Rank Contacts output by opportunity_id — it has ALL fields.
const allContacts = $('Score & Rank Contacts').all();

return $input.all().map((item) => {
  const oppId = item.json.opportunity_id;
  const full = allContacts.find(c => c.json.opportunity_id === oppId);
  return { json: { ...(full ? full.json : {}), ...item.json } };
});

const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 2);
const cutoffStr = cutoff.toISOString().split('T')[0];

// Exclude rows that are approved (any truthy value)
function isApproved(v) {
  if (!v && v !== 0) return false;
  if (v === true || v === 1) return true;
  const s = String(v).trim().toLowerCase();
  return ['true', 'approved', 'yes', '1'].includes(s);
}

function isRejected(v) {
  const s = String(v || '').trim().toLowerCase();
  return s === 'reject' || s === 'rejected';
}

return $input.all().filter(item => {
  const approved = item.json.approved;
  const addedDate = item.json.added_date || '';
  // Skip reject rows — handled by immediate reject branch
  return !isApproved(approved) && !isRejected(approved) && addedDate && addedDate <= cutoffStr;
});

return $input.all().filter(item => {
  const approved = String(item.json.approved || '').trim().toLowerCase();
  return approved === 'reject' || approved === 'rejected';
});

return $('Filter Rejected').all()
  .sort((a, b) => (b.json.row_number || 0) - (a.json.row_number || 0))
  .map(item => ({ json: { row_number: item.json.row_number } }));

const contacts = $input.all();
const opps = $('Extract Hiring Signals').all();

if (opps.length === 0) return [];
const opp = opps[0].json;

const oppName = (opp.company_name || '').toLowerCase().trim();
const oppDomain = (opp.company_domain || '').toLowerCase().trim();

const existingCount = contacts.filter(c => {
  const cDomain = (c.json.company_domain || '').toLowerCase().trim();
  const cName = (c.json.company_name || '').toLowerCase().trim();
  if (oppDomain && cDomain) return cDomain === oppDomain;
  return cName === oppName;
}).length;

return [{ json: { ...opp, hunter_offset: existingCount } }];
